@Override
    public Set<Feature> extract(JCas view1, JCas view2) throws TextClassificationException
    {
        return new Feature("SharedNEs", !Collections.disjoint(getNEs(view1), getNEs(view2)),
                FeatureType.NUMERIC).asSet();

    }
